# -*- coding: utf-8 -*-
import os
import sys

from ._version import __version__  # noqa: F403,F401

if os.name == "nt":  # pragma: no cover
    os.environ["PATH"] = (
        f"{os.path.abspath(os.path.dirname(__file__))}"
        f"{os.pathsep}"
        f"{os.environ['PATH']}"
    )

_pango_available = False
_pango_error = None
_pango_errors = []
# iOS strategy: native Pango when fontconfig is set up, pycairo fallback
# otherwise. The native path's advantage is multi-font fallback — Pango
# draws each character in the first registered font that has a matching
# glyph, so CJK text (Chinese/Japanese/Korean) renders correctly as long
# as we've registered a CJK-capable font alongside KaTeX_Main. The
# pycairo path uses Cairo's toy font API which has NO multi-font fallback
# on this iOS build (no FreeType/Quartz backend linked; it can only draw
# basic Latin via the built-in "twin" stick-figure font). So CJK
# characters are invisible on pycairo but correct on native.
#
# Safety: native Pango SIGSEGVs at first layout if fontconfig can't
# resolve the default "Times 9.999" family — which is the default state
# when nothing has configured fontconfig. That's what crashed offlinai-repl
# on launch before. We gate native on FONTCONFIG_FILE being set — the
# Swift manim bootstrap (PythonRuntime.swift ~line 1081) writes a
# runtime fonts.conf with serif/Times → KaTeX_Main aliases and sets
# FONTCONFIG_FILE BEFORE importing manim. REPL imports skip that
# bootstrap, so they keep using pycairo and don't crash.
#
# Overrides:
#   OFFLINAI_FORCE_PYCAIRO=1 → force pycairo even if fontconfig is set
#   OFFLINAI_FORCE_PYCAIRO=0 → force native even without FONTCONFIG_FILE
#                              (expect a crash unless you know what you're doing)
# Force pycairo unconditionally. Previous attempts to opt into native
# Pango when FONTCONFIG_FILE was set still crashed at 0x8 on Thread 24,
# so the fontconfig alias isn't enough to bypass Pango's init-time
# NULL-deref on this iOS build. Until that's root-caused the only safe
# default is pycairo, and CJK support needs a different mechanism
# (rasterizing via Pillow+FreeType, traced to paths).
_FORCE_PYCAIRO = os.environ.get("OFFLINAI_FORCE_PYCAIRO", "1") == "1"


try:
    if _FORCE_PYCAIRO:
        raise ImportError("OFFLINAI_FORCE_PYCAIRO=1")
    # Try each module individually to get specific errors
    try:
        from ._register_font import *  # Direct import of C module
    except (ImportError, OSError) as e1:
        _pango_errors.append(f"_register_font: {e1}")
        # Try loading the framework directly via ctypes
        import ctypes
        _fw_base = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
        _fw_path = os.path.join(_fw_base, "Frameworks",
            "site-packages.manimpango._register_font.framework",
            "site-packages.manimpango._register_font")
        if os.path.exists(_fw_path):
            try:
                ctypes.CDLL(_fw_path, mode=ctypes.RTLD_GLOBAL)
                from ._register_font import *  # Retry after preload
                _pango_errors.pop()  # Success — remove error
            except Exception as e1b:
                _pango_errors.append(f"_register_font ctypes: {e1b}")

    try:
        from .register_font import *  # Python wrapper
    except (ImportError, OSError) as e1w:
        _pango_errors.append(f"register_font.py: {e1w}")

    try:
        from .cmanimpango import *
    except (ImportError, OSError) as e2:
        _pango_errors.append(f"cmanimpango: {e2}")

    try:
        from .enums import *
    except (ImportError, OSError) as e3:
        _pango_errors.append(f"enums: {e3}")

    if not _pango_errors:
        _pango_available = True
    else:
        _pango_error = "; ".join(_pango_errors)
except Exception as _pe:
    _pango_error = str(_pe)

if not _pango_available:
    # Plain stderr (not `warnings.warn`) — the warnings scaffolding
    # looks like an error and the user explicitly flagged it as noise.
    # Swift's PythonRuntime emits its own "[manim] Pango: …" status
    # line at render time; this one is just for early-import diagnosis.
    _reason = "iOS default (set OFFLINAI_FORCE_PYCAIRO=0 to try native)" \
        if _FORCE_PYCAIRO else (_pango_error or "unknown")
    print(f"[manimpango] pycairo compatibility mode — {_reason}",
          file=sys.stderr, flush=True)

    # ═══════════════════════════════════════════════════════════════
    # Complete manimpango API reimplementation using pycairo
    # Matches all classes, functions, and parameters from the real
    # manimpango 0.6.1 (Pango+Cairo Cython bindings)
    # ═══════════════════════════════════════════════════════════════

    from enum import IntEnum as _IntEnum

    class Style(_IntEnum):
        NORMAL = 0
        ITALIC = 1
        OBLIQUE = 2

    class Weight(_IntEnum):
        THIN = 100
        ULTRALIGHT = 200
        LIGHT = 300
        BOOK = 380
        NORMAL = 400
        MEDIUM = 500
        SEMIBOLD = 600
        BOLD = 700
        ULTRABOLD = 800
        HEAVY = 900
        ULTRAHEAVY = 1000

    class Variant(_IntEnum):
        NORMAL = 0
        SMALL_CAPS = 1

    class Alignment(_IntEnum):
        LEFT = 0
        CENTER = 1
        RIGHT = 2

    class PangoUtils:
        _STYLE_MAP = {'NORMAL': Style.NORMAL, 'ITALIC': Style.ITALIC, 'OBLIQUE': Style.OBLIQUE}
        _WEIGHT_MAP = {
            'NORMAL': Weight.NORMAL, 'BOLD': Weight.BOLD, 'THIN': Weight.THIN,
            'ULTRALIGHT': Weight.ULTRALIGHT, 'LIGHT': Weight.LIGHT, 'BOOK': Weight.BOOK,
            'MEDIUM': Weight.MEDIUM, 'SEMIBOLD': Weight.SEMIBOLD,
            'ULTRABOLD': Weight.ULTRABOLD, 'HEAVY': Weight.HEAVY, 'ULTRAHEAVY': Weight.ULTRAHEAVY,
        }

        @staticmethod
        def str2style(s):
            return PangoUtils._STYLE_MAP.get(str(s).upper(), Style.NORMAL)

        @staticmethod
        def str2weight(s):
            return PangoUtils._WEIGHT_MAP.get(str(s).upper(), Weight.NORMAL)

        @staticmethod
        def remove_last_M(file_path):
            """Remove trailing 'M' from SVG path data (Pango artifact)."""
            if not file_path or not os.path.exists(str(file_path)):
                return file_path
            try:
                with open(str(file_path), 'r') as f:
                    content = f.read()
                # Remove trailing M commands that Pango sometimes adds
                import re
                content = re.sub(r'M\s*"', '"', content)
                with open(str(file_path), 'w') as f:
                    f.write(content)
            except Exception:
                pass
            return file_path

    class TextSetting:
        """Formatting for slices of a Text object (matches real manimpango)."""
        def __init__(self, start=0, end=0, font='', slant='NORMAL', weight='NORMAL',
                     line_num=-1, color=None, is_new_line=False, **kwargs):
            self.start = int(start)
            self.end = int(end)
            self.font = str(font) if font else ''
            self.slant = str(slant) if slant else 'NORMAL'
            self.weight = str(weight) if weight else 'NORMAL'
            self.line_num = int(line_num) if line_num is not None else -1
            self.color = color
            self.is_new_line = is_new_line

    class RegisteredFont:
        def __init__(self, path='', type=''):
            self.path = str(path)
            self.type = str(type)

    registered_fonts = set()

    def register_font(font_path):
        registered_fonts.add(RegisteredFont(str(font_path)))
        return True

    def unregister_font(font_path):
        return True

    def list_fonts():
        return []

    # ── Color parsing helper ──
    def _parse_color(color_str):
        """Parse a color string (#hex or named) to (r, g, b) floats 0-1."""
        if not color_str or not isinstance(color_str, str):
            return (1.0, 1.0, 1.0)
        c = color_str.strip()
        if c.startswith('#') and len(c) >= 7:
            try:
                return (int(c[1:3], 16)/255.0, int(c[3:5], 16)/255.0, int(c[5:7], 16)/255.0)
            except ValueError:
                pass
        # Named colors (subset)
        _names = {'white':(1,1,1), 'black':(0,0,0), 'red':(1,0,0), 'green':(0,0.5,0),
                  'blue':(0,0,1), 'yellow':(1,1,0), 'cyan':(0,1,1), 'magenta':(1,0,1),
                  'orange':(1,0.65,0), 'purple':(0.5,0,0.5), 'gold':(1,0.84,0)}
        return _names.get(c.lower(), (1.0, 1.0, 1.0))

    # ── Cairo font mapping ──
    def _get_cairo_slant(slant_str):
        import cairo
        s = str(slant_str).upper()
        if s == 'ITALIC': return cairo.FONT_SLANT_ITALIC
        if s == 'OBLIQUE': return cairo.FONT_SLANT_OBLIQUE
        return cairo.FONT_SLANT_NORMAL

    def _get_cairo_weight(weight_str):
        import cairo
        w = str(weight_str).upper()
        if w in ('BOLD', 'ULTRABOLD', 'HEAVY', 'ULTRAHEAVY', 'SEMIBOLD'):
            return cairo.FONT_WEIGHT_BOLD
        return cairo.FONT_WEIGHT_NORMAL

    def text2svg(settings, size, line_spacing, disable_liga, file_name,
                 START_X=0, START_Y=0, width=600, height=400, orig_text='',
                 pango_width=None):
        """Render text to SVG in the same shape real Pango produces:
        a ``<defs>`` block defining each unique glyph path once, plus
        one ``<use>`` per character positioned in place.

        Why this structure matters on iOS:
          • `ctx.text_path(longstring) + ctx.fill()` into an SVGSurface
            fuses every glyph into ONE enormous <path> element with
            thousands of bezier points. Manim parses that as ONE
            VMobject, and every animation frame interpolates the
            entire thing. With 30+ Text mobjects in a scene, this is
            the dominant memory hog that tips the jetsam limit.
          • Real Pango/dvisvgm output defines each glyph once and
            references it via <use>. svgelements + manim then build
            N small VMobjects (one per character) — much lighter to
            interpolate and much friendlier to memory.

        We keep per-character glyph paths in the module-level cache
        `_GLYPH_PATH_CACHE` so the same character (e.g. space, 'e',
        't') is only traced via Cairo once per process.
        """
        import os
        text = str(orig_text) if orig_text else " "
        font_size = float(size) if size else 12.0

        if file_name:
            os.makedirs(os.path.dirname(str(file_name)) or '.', exist_ok=True)
            svg_path = str(file_name)
        else:
            import tempfile
            svg_path = os.path.join(tempfile.gettempdir(), 'manim_text.svg')

        try:
            import cairo

            # Measurement + path-extraction context (1×1 dummy surface).
            meas = cairo.ImageSurface(cairo.FORMAT_ARGB32, 1, 1)
            mctx = cairo.Context(meas)

            PATH_MOVE_TO = cairo.PATH_MOVE_TO
            PATH_LINE_TO = cairo.PATH_LINE_TO
            PATH_CURVE_TO = cairo.PATH_CURVE_TO
            PATH_CLOSE_PATH = cairo.PATH_CLOSE_PATH

            def _extract_glyph_path(ch, font_family, slant, weight, fs):
                """Return SVG path-data string for glyph `ch` placed at
                the origin (x=0, baseline y=0). Caches across calls."""
                cache_key = (ch, font_family, slant, weight, fs)
                cached = _GLYPH_PATH_CACHE.get(cache_key)
                if cached is not None:
                    return cached
                mctx.select_font_face(font_family, slant, weight)
                mctx.set_font_size(fs)
                mctx.new_path()
                mctx.move_to(0.0, 0.0)
                try:
                    mctx.text_path(ch)
                except Exception:
                    _GLYPH_PATH_CACHE[cache_key] = ""
                    return ""
                try:
                    path_data = mctx.copy_path()
                except Exception:
                    path_data = []
                parts = []
                for entry in path_data:
                    ptype, pts = entry[0], entry[1]
                    if ptype == PATH_MOVE_TO:
                        parts.append(f"M{pts[0]:.2f} {pts[1]:.2f}")
                    elif ptype == PATH_LINE_TO:
                        parts.append(f"L{pts[0]:.2f} {pts[1]:.2f}")
                    elif ptype == PATH_CURVE_TO:
                        parts.append(
                            f"C{pts[0]:.2f} {pts[1]:.2f} "
                            f"{pts[2]:.2f} {pts[3]:.2f} "
                            f"{pts[4]:.2f} {pts[5]:.2f}"
                        )
                    elif ptype == PATH_CLOSE_PATH:
                        parts.append("Z")
                d = " ".join(parts)
                _GLYPH_PATH_CACHE[cache_key] = d
                return d

            def _advance_for(ch, font_family, slant, weight, fs):
                mctx.select_font_face(font_family, slant, weight)
                mctx.set_font_size(fs)
                return mctx.text_extents(ch).x_advance

            # Collect unique glyph definitions + per-character placements.
            # Per-SVG scope: d_to_local_id maps a path-data string to the
            # glyph id we assigned inside THIS svg's <defs>. Don't share
            # ids across svgs — each svg must be self-contained.
            defs = {}           # local glyph_id → path-data
            d_to_local_id = {}  # path-data → local glyph_id (dedupe within svg)
            uses = []           # list of (glyph_id_str, x, y, color_hex)
            offset_x = 0.0
            last_line_num = 0

            def _rgb_hex(color_str):
                r, g, b = _parse_color(color_str)
                return f"#{int(round(r*255)):02x}{int(round(g*255)):02x}{int(round(b*255)):02x}"

            # Per-character font switching for CJK. Cairo's toy font API
            # picks one font at select_font_face() time and doesn't fall
            # back across fonts when a glyph is missing — it just draws
            # a box (or nothing). So when the text contains Chinese /
            # Japanese / Korean characters and the selected Latin font
            # has no such glyphs, we swap to a CJK-capable family per
            # character.
            #
            # Finding the right family NAME is finicky: a Noto OTF's
            # nameID-1 (what fontconfig matches on) is sometimes
            # "Noto Sans JP", sometimes "Noto Sans JP Regular", and
            # sometimes "NotoSansJP-Regular". Probe each candidate once
            # at first use by testing whether `text_path("中")` emits
            # actual glyph geometry — the first name that produces a
            # non-empty path is the one Cairo can resolve. Cache the
            # winner for all subsequent CJK glyphs in this process.
            if "resolved" not in _CJK_FAMILY_CACHE:
                _probe_ctx = cairo.Context(
                    cairo.ImageSurface(cairo.FORMAT_ARGB32, 1, 1))
                _probe_ctx.set_font_size(32.0)
                _probe_char = "中"
                _winner = None
                for _cand in ("Noto Sans JP", "Noto Sans JP Regular",
                              "NotoSansJP-Regular", "NotoSansJP",
                              "Noto Sans CJK JP", "Noto Sans",
                              # Hail-mary direct paths — pycairo's toy
                              # API on iOS has accepted absolute font
                              # file paths in some builds.
                              "/KaTeX/fonts/NotoSansJP-Regular.otf"):
                    try:
                        _probe_ctx.select_font_face(
                            _cand, cairo.FONT_SLANT_NORMAL,
                            cairo.FONT_WEIGHT_NORMAL)
                        _probe_ctx.new_path()
                        _probe_ctx.move_to(0.0, 0.0)
                        _probe_ctx.text_path(_probe_char)
                        _path = _probe_ctx.copy_path()
                        if any(True for _ in _path):
                            _winner = _cand
                            break
                    except Exception:
                        continue
                _CJK_FAMILY_CACHE["resolved"] = _winner or "Noto Sans JP"
                print(f"[manimpango] CJK font resolved to: "
                      f"{_CJK_FAMILY_CACHE['resolved']!r}",
                      file=sys.stderr, flush=True)
            _CJK_FAMILY = _CJK_FAMILY_CACHE["resolved"]

            def _is_cjk(cp: int) -> bool:
                # CJK Unified Ideographs + extensions, Hiragana/Katakana,
                # Hangul syllables, full-width ASCII, CJK symbols/punct.
                return (
                    0x3000 <= cp <= 0x30FF       # CJK symbols + Hiragana/Katakana
                    or 0x3400 <= cp <= 0x4DBF    # CJK Ext A
                    or 0x4E00 <= cp <= 0x9FFF    # CJK Unified Ideographs
                    or 0xAC00 <= cp <= 0xD7AF    # Hangul syllables
                    or 0xF900 <= cp <= 0xFAFF    # CJK Compat Ideographs
                    or 0xFF00 <= cp <= 0xFFEF    # Halfwidth/Fullwidth forms
                    or 0x20000 <= cp <= 0x2FFFF  # CJK Ext B-F supplementary
                )

            for setting in (settings or []):
                default_family = setting.font or "sans-serif"
                cslant = _get_cairo_slant(setting.slant)
                cweight = _get_cairo_weight(setting.weight)
                color = _rgb_hex(setting.color)

                if setting.line_num != last_line_num:
                    offset_x = 0.0
                    last_line_num = setting.line_num

                y_pos = (float(START_Y)
                         + float(line_spacing) * setting.line_num
                         + font_size)
                x_pos = float(START_X) + offset_x

                chunk = text[setting.start:setting.end].replace("\n", " ")
                if not chunk:
                    continue

                for ch in chunk:
                    font_family = _CJK_FAMILY if _is_cjk(ord(ch)) else default_family
                    adv = _advance_for(ch, font_family, cslant, cweight, font_size)
                    if ch.strip():
                        d = _extract_glyph_path(ch, font_family, cslant, cweight, font_size)
                        if d:
                            gid = d_to_local_id.get(d)
                            if gid is None:
                                gid = f"g{len(defs)}"
                                d_to_local_id[d] = gid
                                defs[gid] = d
                            uses.append((gid, x_pos, y_pos, color))
                    x_pos += adv
                    offset_x += adv

            # Assemble SVG. Earlier attempts used <defs>+<use> (Pango's
            # canonical shape), but svgelements (manim's SVG parser)
            # doesn't reliably cascade fill/color through <use> —
            # resulting in invisible text even when the defs are
            # correct. On top of that its viewBox defaulting drops
            # paths to ~1/6th scale. Bake EVERYTHING into per-glyph
            # <path> elements — no indirection, no cascade, no
            # viewBox heuristics. Costs a few kilobytes of extra SVG
            # per Text mobject (negligible) in exchange for text that
            # renders deterministically.
            #
            # d_by_id is still used internally (glyph extraction is
            # cached across placements of the same char) but the
            # final emitted XML is strictly <path d="…" transform="…"
            # fill="#rrggbb" fill-rule="nonzero"/> with ALL attributes
            # present, so any SVG parser that understands basic paths
            # renders correctly.
            parts = [
                f'<svg xmlns="http://www.w3.org/2000/svg" '
                f'width="{width}" height="{height}" '
                f'viewBox="0 0 {width} {height}">',
            ]
            for gid, x, y, color in uses:
                d = defs.get(gid, "")
                if not d:
                    continue
                parts.append(
                    f'<path d="{d}" '
                    f'transform="translate({x:.2f},{y:.2f})" '
                    f'fill="{color}" fill-rule="nonzero" '
                    f'fill-opacity="1" stroke="none"/>'
                )
            parts.append('</svg>')

            svg_bytes = ''.join(parts)
            with open(svg_path, 'w', encoding='utf-8') as f:
                f.write(svg_bytes)

            # Diagnostic dump on first call per process — lets the user
            # inspect the SVG output from the fallback and verify that
            # the text is at least reaching the renderer. Overwrite-in-
            # place so the file never grows unbounded.
            global _DIAG_DUMP_COUNT
            try:
                _DIAG_DUMP_COUNT
            except NameError:
                _DIAG_DUMP_COUNT = 0
            if _DIAG_DUMP_COUNT < 3:
                try:
                    import tempfile as _tf
                    dump = os.path.join(_tf.gettempdir(),
                                        f"manim_text_dump_{_DIAG_DUMP_COUNT}.svg")
                    with open(dump, 'w', encoding='utf-8') as _df:
                        _df.write(svg_bytes)
                    print(f"[manimpango] dumped text2svg output → {dump}  "
                          f"({len(text)}ch, {len(defs)} unique glyphs, "
                          f"{len(uses)} placements)", flush=True)
                    _DIAG_DUMP_COUNT += 1
                except OSError:
                    pass
            meas.finish()
            return svg_path

        except ImportError:
            # Cairo not available — minimal SVG fallback.
            esc = text.replace('&','&amp;').replace('<','&lt;').replace('>','&gt;')
            svg = (f'<svg xmlns="http://www.w3.org/2000/svg" width="{width}" height="{height}">'
                   f'<text x="{START_X}" y="{font_size}" font-size="{font_size}" fill="white">{esc}</text></svg>')
            with open(svg_path, 'w') as f:
                f.write(svg)
            return svg_path

    # Module-level glyph path cache — same character, same font, same
    # size → same path-data string. Per-SVG dedup happens via the
    # d_to_local_id dict inside text2svg.
    _GLYPH_PATH_CACHE: dict = {}

    # Module-level cache for the CJK family-name probe result.
    # Populated by text2svg on the first CJK character it encounters
    # and reused thereafter to avoid re-probing every call.
    _CJK_FAMILY_CACHE: dict = {}

    def markup2svg(text, font='', slant='NORMAL', weight='NORMAL', size=1,
                   _placeholder=None, disable_ligatures=False, file_name='',
                   START_X=0, START_Y=0, width=600, height=400, **kwargs):
        """Render markup text to SVG (strips markup tags, delegates to text2svg)."""
        import re
        plain = re.sub(r'<[^>]+>', '', str(text))
        settings = [TextSetting(start=0, end=len(plain), font=font, slant=slant,
                                weight=weight, color='white')]
        return text2svg(settings, size, 0, disable_ligatures, file_name,
                       START_X, START_Y, width, height, plain)

    class MarkupUtils:
        @staticmethod
        def validate(markup):
            """Validate Pango markup. Returns empty string (valid) on iOS."""
            return ""

        @staticmethod
        def text2svg(text, font=None, slant='NORMAL', weight='NORMAL', size=1,
                     _placeholder=None, disable_liga=False, file_name='',
                     START_X=0, START_Y=0, width=600, height=400, *,
                     justify=None, indent=None, line_spacing=None,
                     alignment=None, pango_width=None):
            """Render Pango markup to SVG via Cairo (same as text2svg)."""
            import re
            plain = re.sub(r'<[^>]+>', '', str(text))
            settings = [TextSetting(start=0, end=len(plain), font=font or '',
                                    slant=slant, weight=weight, color='white')]
            return text2svg(settings, size, line_spacing or 0, disable_liga, file_name,
                           START_X, START_Y, width, height, plain,
                           pango_width=pango_width)

    def pango_version():
        return "1.50.0"

    def cairo_version():
        try:
            import cairo
            return cairo.cairo_version_string()
        except Exception:
            return "1.16.0"

